-- ============================================================
-- Indian Stocks Seed Data (FIXED - no duplicate yahoo_symbols)
-- Uses CTE with DISTINCT ON to handle any remaining duplicates
-- Run this in Supabase SQL Editor
-- ============================================================

-- Step 1: Create table (safe to re-run)
CREATE TABLE IF NOT EXISTS indian_stocks (
  id          SERIAL PRIMARY KEY,
  symbol      TEXT NOT NULL,
  yahoo_symbol TEXT NOT NULL,
  company_name TEXT NOT NULL,
  exchange    TEXT NOT NULL CHECK (exchange IN ('NSE','BSE','NSE,BSE')),
  sector      TEXT,
  industry    TEXT,
  series      TEXT DEFAULT 'EQ',
  created_at  TIMESTAMPTZ DEFAULT NOW()
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_is_yahoo_symbol ON indian_stocks(yahoo_symbol);
CREATE INDEX IF NOT EXISTS idx_is_symbol   ON indian_stocks(symbol);
CREATE INDEX IF NOT EXISTS idx_is_exchange ON indian_stocks(exchange);
CREATE INDEX IF NOT EXISTS idx_is_sector   ON indian_stocks(sector);
CREATE INDEX IF NOT EXISTS idx_is_search   ON indian_stocks
  USING GIN (to_tsvector('english', company_name || ' ' || symbol));

