),
deduped AS (
  SELECT DISTINCT ON (yahoo_symbol) symbol, yahoo_symbol, company_name, exchange, sector, industry
  FROM raw_data
  ORDER BY yahoo_symbol
)
INSERT INTO indian_stocks (symbol, yahoo_symbol, company_name, exchange, sector, industry)
SELECT * FROM deduped
ON CONFLICT (yahoo_symbol) DO UPDATE SET
  company_name = EXCLUDED.company_name,
  sector       = EXCLUDED.sector,
  industry     = EXCLUDED.industry;

-- Verify result
SELECT exchange, COUNT(*) AS total FROM indian_stocks GROUP BY exchange ORDER BY exchange;
